public class Example {
    public Example() {
        Exception result = attempt(() -> {});
        if (result != null) {
            throw new RuntimeException(result);
        }
    }

    private Exception attempt(Runnable task) {
        try {
            task.run();
            return null;
        } catch (Exception e) {
            // src/Example.java:15:    UnnecessaryLocalBeforeReturnOrThrows:   Consider simply returning the value vs storing it in local variable 'e'
            return e;
        }
    }
}

